"""
Evaluation result models produced by validators.
"""
from __future__ import annotations

from datetime import datetime
from typing import Any, Dict, Optional

from pydantic import BaseModel, ConfigDict, Field, field_validator

from app.utils.datetime import to_datetime


class EvaluationResult(BaseModel):
    """Evaluation results generated by the validator."""

    task_id: Optional[str] = None
    agent_run_id: Optional[str] = None
    metrics: Dict[str, Any] = Field(default_factory=dict)
    score: Optional[float] = None
    reward: Optional[float] = None
    response_time: Optional[float] = None
    feedback: Dict[str, Any] = Field(default_factory=dict)

    model_config = ConfigDict(from_attributes=True)


class EvaluationResultRead(EvaluationResult):
    """Evaluation result retrieved from persistent storage."""

    id: str
    created_at: datetime

    model_config = ConfigDict(from_attributes=True)

    @field_validator("created_at", mode="before")
    @classmethod
    def _coerce_created_at(cls, value: Any) -> datetime:
        result = to_datetime(value)
        if result is None:
            raise ValueError("created_at cannot be null")
        return result
